'use client';

import { useState, useRef, useEffect } from 'react';
import styles from './intake.module.css';
import { Send, User, Bot, Sparkles, Calendar, MessageCircle, ArrowRight } from 'lucide-react';
import { Coach } from '@/lib/data/sample-coaches';

interface Message {
    role: 'user' | 'assistant';
    content: string;
    matches?: { coach: Coach; explanation: string; score: number }[];
}

export default function IntakeChat() {
    const [messages, setMessages] = useState<Message[]>([
        {
            role: 'assistant',
            content: "Hi. I'm here to help you find the kind of support that feels right for you. You can tell me as much or as little as you want. What has been weighing on you lately?"
        }
    ]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const scrollRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages]);

    const fetchMatches = async (userInput: string) => {
        try {
            const res = await fetch('/api/ai/match', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ userInput }),
            });
            const data = await res.json();
            return data.matches;
        } catch (e) {
            console.error('Match error', e);
            return [];
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim() || isLoading) return;

        const currentInput = input;
        const userMessage: Message = { role: 'user', content: currentInput };
        setMessages(prev => [...prev, userMessage]);
        setInput('');
        setIsLoading(true);

        try {
            const response = await fetch('/api/ai/chat', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ messages: [...messages, userMessage] }),
            });

            if (!response.body) throw new Error('No response body');

            const reader = response.body.getReader();
            const decoder = new TextDecoder();
            let assistantContent = '';

            const assistantMessagePlaceholder: Message = { role: 'assistant', content: '' };
            setMessages(prev => [...prev, assistantMessagePlaceholder]);

            while (true) {
                const { done, value } = await reader.read();
                if (done) break;

                const token = decoder.decode(value);
                assistantContent += token;

                setMessages(prev => {
                    const updated = [...prev];
                    updated[updated.length - 1] = { ...updated[updated.length - 1], content: assistantContent };
                    return updated;
                });
            }

            // After assistant finishes, check if we should suggest coaches
            // Logic: Show matches immediately if possible, or after first interaction
            const combinedInput = messages.concat(userMessage).map(m => m.content).join(' ');
            const matches = await fetchMatches(combinedInput);

            if (matches && matches.length > 0) {
                setMessages(prev => [
                    ...prev,
                    {
                        role: 'assistant',
                        content: "Jag har hittat några coacher som jag tror skulle passa dig bra baserat på det du berättat. Vill du titta på dem?",
                        matches
                    }
                ]);
            }

        } catch (error) {
            console.error('Chat error:', error);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className={styles.container}>
            <div className={styles.chatWindow}>
                <div className={styles.messages} ref={scrollRef}>
                    {messages.map((msg, idx) => (
                        <div key={idx} className={styles.messageGroup}>
                            <div className={`${styles.messageWrapper} ${styles[msg.role]}`}>
                                <div className={styles.avatar}>
                                    {msg.role === 'assistant' ? <Bot size={20} /> : <User size={20} />}
                                </div>
                                <div className={styles.bubble}>
                                    {msg.content}
                                </div>
                            </div>

                            {msg.matches && (
                                <div className={styles.matchContainer}>
                                    {msg.matches.map((match: any) => (
                                        <div key={match.coach.id} className={styles.coachCard}>
                                            <div className={styles.coachHeader}>
                                                <img src={match.coach.imageUrl} alt={match.coach.name} className={styles.coachAvatar} />
                                                <div>
                                                    <p className={styles.coachName}>{match.coach.name}</p>
                                                    <p className={styles.coachTitle}>{match.coach.title}</p>
                                                </div>
                                            </div>
                                            <p className={styles.matchExplanation}>{match.explanation}</p>
                                            <div className={styles.coachActions}>
                                                <button className={styles.chatAction}><MessageCircle size={16} /> Chat</button>
                                                <button className={styles.bookAction}><Calendar size={16} /> Book</button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    ))}
                    {isLoading && messages[messages.length - 1].role === 'user' && (
                        <div className={`${styles.messageWrapper} ${styles.assistant}`}>
                            <div className={styles.avatar}>
                                <Sparkles size={20} className={styles.pulse} />
                            </div>
                            <div className={styles.bubble}>
                                Looking for the best support for you...
                            </div>
                        </div>
                    )}
                </div>

                <form onSubmit={handleSubmit} className={styles.inputArea}>
                    <input
                        type="text"
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        placeholder="Type your thoughts here..."
                        className={styles.input}
                        disabled={isLoading}
                    />
                    <button type="submit" className={styles.sendBtn} disabled={isLoading || !input.trim()}>
                        <Send size={20} />
                    </button>
                </form>
            </div>

            <div className={styles.sidebar}>
                <div className={styles.sideCard}>
                    <h3>Your Safe Space</h3>
                    <p>Take your time. You do not need to explain everything at once.</p>
                </div>

                <div className={styles.privacyNote}>
                    Your conversations stay private. The AI helps with matching. You choose what happens next.
                </div>

                <div className={styles.guideCard}>
                    <h4>Next Step</h4>
                    <p>After you describe your situation, we'll introduce you to human experts who can help.</p>
                    <ArrowRight size={20} style={{ marginTop: 'var(--spacing-sm)', color: 'var(--accent-sage)' }} />
                </div>
            </div>
        </div>
    );
}
